        # --- FUNCIÓN DE LÓGICA DE GRAFICACIÓN ---
    def graficar(self):
        try:
            # Obtener valores de los Edit Text
            min_val = float(self.textEdit.toPlainText())
            max_val = float(self.textEdit_2.toPlainText())

            # Crear rango de datos
            x = np.linspace(min_val, max_val, 1000)
            
            # Obtener selección del Pop Up Menu
            seleccion = self.comboBox.currentText()

            # Calcular función
            if seleccion == "SENO":
                y = np.sin(x)
            elif seleccion == "COSENO":
                y = np.cos(x)
            elif seleccion == "TANGENTE":
                y = np.tan(x)
                y[np.abs(y) > 10] = np.nan # Evitar líneas verticales en asíntotas
            elif seleccion == "SECANTE":
                y = 1 / np.cos(x)
                y[np.abs(y) > 10] = np.nan
            elif seleccion == "COSECANTE":
                y = 1 / np.sin(x)
                y[np.abs(y) > 10] = np.nan
            elif seleccion == "COTANGENTE":
                y = 1 / np.tan(x)
                y[np.abs(y) > 10] = np.nan

            # Dibujar en el objeto Axes
            self.canvas.axes.clear()
            self.canvas.axes.plot(x, y, color='blue', label=seleccion)
            # --- AGREGAR TÍTULOS A LOS EJES ---
            self.canvas.axes.set_title(f"Gráfica de {seleccion}")
            self.canvas.axes.set_xlabel("Eje X (Radianes)") # Título eje horizontal
            self.canvas.axes.set_ylabel("Eje Y (Amplitud)") # Título eje vertical
            self.canvas.axes.set_title(f"Gráfica de {seleccion}")
            self.canvas.axes.grid(True)
            self.canvas.axes.legend()
            self.canvas.draw()

        except ValueError:
            # En caso de que los Edit Text no tengan números válidos
            msg = QtWidgets.QMessageBox()
            msg.setIcon(QtWidgets.QMessageBox.Warning)
            msg.setText("Por favor ingrese valores numéricos válidos en los rangos.")
            msg.exec_()
